import React, { useState, useEffect } from 'react';
import {
  Box,
  Paper,
  TextField,
  Button,
  Typography,
  Link,
  Alert,
  CircularProgress,
  Container,
  InputAdornment,
  IconButton
} from '@mui/material';
import {
  Visibility,
  VisibilityOff,
  Email,
  Lock,
  Instagram,
  YouTube,
  Telegram as TelegramIcon
} from '@mui/icons-material';
import { Link as RouterLink } from 'react-router-dom';
import { toast } from 'react-toastify';
import { useAuth } from '../../contexts/AuthContext';

const Login = () => {
  const { login } = useAuth();
  const [formData, setFormData] = useState({
    email: '',
    password: ''
  });
  const [showPassword, setShowPassword] = useState(false);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');
  const [videoLoaded, setVideoLoaded] = useState(false);
  const [showLogin, setShowLogin] = useState(false);
  const [loadingProgress, setLoadingProgress] = useState(0);

  const fullText = 'Nautilus Automação';

  useEffect(() => {
    const progressInterval = setInterval(() => {
      setLoadingProgress(prev => {
        if (prev >= 90 && !videoLoaded) {
          return 90;
        }
        if (videoLoaded && prev >= 100) {
          clearInterval(progressInterval);
          setTimeout(() => {
            setShowLogin(true);
          }, 800);
          return 100;
        }
        return prev + (videoLoaded ? 15 : 8);
      });
    }, 200);

    const maxTimeout = setTimeout(() => {
      clearInterval(progressInterval);
      setLoadingProgress(100);
      setVideoLoaded(true);
      setTimeout(() => {
        setShowLogin(true);
      }, 500);
    }, 12000);

    return () => {
      clearInterval(progressInterval);
      clearTimeout(maxTimeout);
    };
  }, [videoLoaded]);

  const handleChange = (e) => {
    const { name, value } = e.target;
    setFormData(prev => ({
      ...prev,
      [name]: value
    }));
    if (error) setError('');
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setError('');

    if (!formData.email || !formData.password) {
      setError('Todos os campos são obrigatórios');
      setLoading(false);
      return;
    }

    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!emailRegex.test(formData.email)) {
      setError('Formato de email inválido');
      setLoading(false);
      return;
    }

    try {
      const result = await login(formData.email, formData.password);

      if (result.success) {
        toast.success('Login realizado com sucesso!');
      } else {
        setError(result.message || 'Erro ao fazer login');
        toast.error(result.message || 'Erro ao fazer login');
      }
    } catch (error) {
      console.error('Erro no login:', error);
      setError('Erro ao fazer login. Tente novamente.');
      toast.error('Erro ao fazer login');
    } finally {
      setLoading(false);
    }
  };

  const togglePasswordVisibility = () => {
    setShowPassword(!showPassword);
  };

  const handleVideoLoad = () => {
    console.log('Vídeo carregado com sucesso!');
    setVideoLoaded(true);
  };

  const handleVideoError = () => {
    console.log('Erro no carregamento do vídeo, continuando...');
    setVideoLoaded(true);
  };

  if (!showLogin) {
    return (
      <Box
        sx={{
          minHeight: '100vh',
          background: 'linear-gradient(135deg, #0a0a0a 0%, #1a1a2e 25%, #16213e 50%, #1a1a2e 75%, #0a0a0a 100%)',
          position: 'relative',
          overflow: 'hidden',
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          padding: 2
        }}
      >
        <Box
          sx={{
            position: 'absolute',
            top: '-9999px',
            left: '-9999px',
            opacity: 0,
            pointerEvents: 'none'
          }}
        >
          <iframe
            src="https://player.vimeo.com/video/1093368764?autoplay=0&loop=1&muted=1&background=1&controls=0&quality=hd720&autopause=0&dnt=1&title=0&byline=0&portrait=0#t=0"
            width="100"
            height="100"
            frameBorder="0"
            allow="autoplay; fullscreen; picture-in-picture"
            onLoad={handleVideoLoad}
            onError={handleVideoError}
            title="Background Video Preload"
          />
        </Box>

        <Typography
          variant="h3"
          sx={{
            color: '#ffffff',
            fontWeight: 'bold',
            textAlign: 'center',
            mb: 4,
            textShadow: '0 2px 10px rgba(0,0,0,0.5)',
            letterSpacing: '2px'
          }}
        >
          {fullText}
        </Typography>

        <Box sx={{ width: '300px', mb: 2 }}>
          <Box
            sx={{
              width: '100%',
              height: '4px',
              backgroundColor: 'rgba(255,255,255,0.1)',
              borderRadius: '2px',
              overflow: 'hidden',
              position: 'relative'
            }}
          >
            <Box
              sx={{
                width: `${loadingProgress}%`,
                height: '100%',
                background: 'linear-gradient(90deg, #00bcd4, #2196f3, #3f51b5)',
                borderRadius: '2px',
                transition: 'width 0.3s ease',
                position: 'relative',
                '&::after': {
                  content: '""',
                  position: 'absolute',
                  top: 0,
                  left: 0,
                  right: 0,
                  bottom: 0,
                  background: 'linear-gradient(90deg, transparent, rgba(255,255,255,0.4), transparent)',
                  animation: 'shimmer 2s infinite'
                }
              }}
            />
          </Box>
        </Box>

        <Typography
          variant="body1"
          sx={{
            color: '#cccccc',
            textAlign: 'center',
            fontSize: '16px'
          }}
        >
          Carregando plataforma... {Math.round(loadingProgress)}%
        </Typography>

        {process.env.NODE_ENV === 'development' && (
          <Typography
            variant="caption"
            sx={{
              color: '#666',
              mt: 2,
              fontSize: '12px'
            }}
          >
            Vídeo: {videoLoaded ? '✓ Carregado' : '⏳ Carregando...'}
          </Typography>
        )}

        <style>
          {`
            @keyframes shimmer {
              0% { transform: translateX(-100%); }
              100% { transform: translateX(300%); }
            }
          `}
        </style>
      </Box>
    );
  }

  return (
    <Box
      sx={{
        minHeight: '100vh',
        background: 'linear-gradient(135deg, #0a0a0a 0%, #1a1a2e 25%, #16213e 50%, #1a1a2e 75%, #0a0a0a 100%)',
        position: 'relative',
        overflow: 'hidden',
        display: 'flex',
        alignItems: 'center',
        justifyContent: 'center',
        padding: 2,
        animation: 'fadeIn 1s ease-in-out'
      }}
    >
      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          zIndex: 0,
          '& iframe': {
            width: '100%',
            height: '100%',
            objectFit: 'cover'
          }
        }}
      >
        <iframe
          src="https://player.vimeo.com/video/1093368764?autoplay=1&loop=1&muted=1&background=1&controls=0&quality=hd720&autopause=0&dnt=1&title=0&byline=0&portrait=0#t=0"
          width="100%"
          height="100%"
          frameBorder="0"
          allow="autoplay; fullscreen; picture-in-picture"
          allowFullScreen
          title="Background Video"
          style={{
            filter: 'contrast(1.1) brightness(0.9) saturate(1.1)',
            willChange: 'transform, opacity',
            backgroundColor: '#0a0a0a'
          }}
        />
      </Box>

      <Box
        sx={{
          position: 'absolute',
          top: 0,
          left: 0,
          width: '100%',
          height: '100%',
          backgroundColor: 'rgba(0, 0, 0, 0.4)',
          zIndex: 2
        }}
      />

      <Container component="main" maxWidth="xs" sx={{ zIndex: 4, position: 'relative' }}>
        <Paper
          elevation={24}
          sx={{
            padding: 4,
            display: 'flex',
            flexDirection: 'column',
            alignItems: 'center',
            backgroundColor: 'rgba(255, 255, 255, 0.95)',
            backdropFilter: 'blur(10px)',
            borderRadius: 3,
            border: '1px solid rgba(255, 255, 255, 0.2)',
            boxShadow: '0 25px 50px -12px rgba(0, 0, 0, 0.5)'
          }}
        >
          <Box sx={{ textAlign: 'center', mb: 3 }}>
            <Typography
              variant="h4"
              sx={{
                fontWeight: 'bold',
                background: 'linear-gradient(45deg, #1976d2, #42a5f5)',
                backgroundClip: 'text',
                WebkitBackgroundClip: 'text',
                color: 'transparent',
                mb: 1
              }}
            >
              Nautilus
            </Typography>
            <Typography variant="body2" color="text.secondary">
              Automação Inteligente para Trading
            </Typography>
          </Box>

          {error && (
            <Alert 
              severity="error" 
              sx={{ width: '100%', mb: 2 }}
              onClose={() => setError('')}
            >
              {error}
            </Alert>
          )}

          <Box component="form" onSubmit={handleSubmit} sx={{ width: '100%' }}>
            <TextField
              margin="normal"
              required
              fullWidth
              id="email"
              label="Email"
              name="email"
              autoComplete="email"
              autoFocus
              value={formData.email}
              onChange={handleChange}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Email color="action" />
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  '&:hover fieldset': {
                    borderColor: '#1976d2',
                  },
                }
              }}
            />
            <TextField
              margin="normal"
              required
              fullWidth
              name="password"
              label="Senha"
              type={showPassword ? 'text' : 'password'}
              id="password"
              autoComplete="current-password"
              value={formData.password}
              onChange={handleChange}
              InputProps={{
                startAdornment: (
                  <InputAdornment position="start">
                    <Lock color="action" />
                  </InputAdornment>
                ),
                endAdornment: (
                  <InputAdornment position="end">
                    <IconButton
                      aria-label="toggle password visibility"
                      onClick={togglePasswordVisibility}
                      edge="end"
                    >
                      {showPassword ? <VisibilityOff /> : <Visibility />}
                    </IconButton>
                  </InputAdornment>
                ),
              }}
              sx={{
                '& .MuiOutlinedInput-root': {
                  '&:hover fieldset': {
                    borderColor: '#1976d2',
                  },
                }
              }}
            />
            <Button
              type="submit"
              fullWidth
              variant="contained"
              disabled={loading}
              sx={{
                mt: 3, 
                mb: 2,
                py: 1.5,
                background: 'linear-gradient(45deg, #1976d2, #42a5f5)',
                '&:hover': {
                  background: 'linear-gradient(45deg, #1565c0, #1976d2)',
                },
                '&:disabled': {
                  background: 'rgba(0, 0, 0, 0.12)',
                }
              }}
            >
              {loading ? (
                <CircularProgress size={24} color="inherit" />
              ) : (
                'Entrar'
              )}
            </Button>
          </Box>

          <Box sx={{ textAlign: 'center', mt: 2 }}>
            <Typography variant="body2" color="text.secondary" gutterBottom>
              Não tem uma conta?
            </Typography>
            <Link
              component={RouterLink}
              to="/register"
              variant="body2"
              sx={{
                color: '#1976d2',
                textDecoration: 'none',
                fontWeight: 'medium',
                '&:hover': {
                  textDecoration: 'underline',
                }
              }}
            >
              Cadastre-se aqui
            </Link>
          </Box>

          <Box sx={{ 
            display: 'flex', 
            justifyContent: 'center', 
            gap: 2, 
            mt: 3,
            pt: 2,
            borderTop: '1px solid rgba(0, 0, 0, 0.1)'
          }}>
            <IconButton
              href="https://instagram.com/nautilusautomacao"
              target="_blank"
              rel="noopener noreferrer"
              sx={{
                color: '#E4405F',
                '&:hover': {
                  backgroundColor: 'rgba(228, 64, 95, 0.1)',
                }
              }}
            >
              <Instagram />
            </IconButton>
            <IconButton
              href="https://youtube.com/@nautilusautomacao"
              target="_blank"
              rel="noopener noreferrer"
              sx={{
                color: '#FF0000',
                '&:hover': {
                  backgroundColor: 'rgba(255, 0, 0, 0.1)',
                }
              }}
            >
              <YouTube />
            </IconButton>
            <IconButton
              href="https://t.me/nautilusautomacao"
              target="_blank"
              rel="noopener noreferrer"
              sx={{
                color: '#0088cc',
                '&:hover': {
                  backgroundColor: 'rgba(0, 136, 204, 0.1)',
                }
              }}
            >
              <TelegramIcon />
